/* Botón de acordeón: ancho completo, texto a la izquierda, espacio para el icono */
[selector='accordiones'] .btn-primary {
  width: 100%;
  text-align: left;
  position: relative;
  padding-right: 37px; /* espacio para la flecha (FontAwesome) */
  /* Transición suave para cambios de fondo o color si los hubiera */
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* Pseudo-elemento ::after que inserta la flecha con Font Awesome */
[selector='accordiones'] .btn-primary::after {
  /* FontAwesome 5 Free: Unicode f078 = "chevron-down" */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f078";
  position: absolute;
  top: 50%;
  right: 0.75rem;
  transform: translateY(-50%) rotate(0deg);
  font-size: 1rem;
  color: #ffffff;
  /* Transición suave al rotar la flecha */
  transition: transform 0.3s ease-in-out;
}

/* Cuando el botón tenga la clase .open (panel abierto), girar la flecha */
[selector='accordiones'] .btn-primary.open::after {
  transform: translateY(-50%) rotate(180deg);
}

/* Opcional: cambiar ligeramente el fondo al pasar el ratón */
[selector='accordiones'] .btn-primary:hover {
  background-color: #1b5c99;
}


