:root {
  --accent: #2167AE;     /* Azul institucional */
  --success: #2ea043;    /* Verde de confirmación */
  --bg: #f7f9fc;
  --card: #ffffff;
  --border: #e5e7eb;
  --shadow: 0 8px 20px rgba(0,0,0,0.08);
  --warning: #f59e0b;    /* Naranja de advertencia ligera */
   --danger: #dc2626; /* Rojo para errores */
}

/* Contenedor principal */
[selector="completado-screen"] {
  min-height: 50vh;
  display: grid;
  place-items: center;
  padding: 24px;
  background: var(--bg);
  color: var(--accent) !important;
}

[selector="completado-screen"] .wrap, 
[selector="completado-screen"] .wrap * {
  color: var(--accent) !important;
}

[selector="completado-screen"] .wrap {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 16px;
  box-shadow: var(--shadow);
  padding: clamp(28px, 4vw, 44px);
  text-align: center;
  animation: fadeIn .6s ease both;
}

/* Ícono general (check grande superior) */
[selector="completado-screen"] .wrap::before {
  content: "\f00c"; /* fa-check */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  display: block;
  font-size: 3rem;
  color: var(--success) !important;
  margin-bottom: 14px;
  line-height: 1;
}

/* Título */
[selector="completado-screen"] .titulo {
  font-size: 1.5rem;
  font-weight: 700;
  margin-bottom: 6px;
}

/* Párrafos descriptivos */
[selector="completado-screen"] .descripcion {
  font-size: 0.98rem;
  margin: 6px 0;
}

/* Línea con icono + texto (para correos) */
[selector="completado-screen"] .linea-icono {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  margin-top: 10px;
  font-size: 0.98rem;
}

/* Iconos específicos */
[selector="completado-screen"] .icon-success {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  font-size: 1.1rem;
  color: var(--success) !important;
}

[selector="completado-screen"] .icon-warning {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  font-size: 1.1rem;
  color: var(--warning) !important;
}

/* Badge para lista de correos / número de caso */
[selector="completado-screen"] .numero-caso {
  display: inline-block;
  margin: 12px 0 8px;
  font-weight: 700;
  font-size: 1.05rem;
  letter-spacing: 0.3px;
  padding: 8px 16px;
  border-radius: 999px;
  background: rgba(33,103,174,0.08);
  border: 1px solid var(--accent);
  color: var(--accent) !important;
  word-break: break-word;
}

/* Nota final */
[selector="completado-screen"] .nota {
  margin-top: 18px;
  font-size: 0.95rem;
  background: rgba(33,103,174,0.05);
  border: 1px dashed var(--accent);
  padding: 12px 16px;
  border-radius: 12px;
  color: var(--accent) !important;
}

/* Botón Continuar */
[selector="completado-screen"] .btn-continuar {
  margin-top: 20px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 24px;
  border-radius: 999px;
  border: none;
  background: var(--accent);
  color: #ffffff !important;
  font-size: 0.98rem;
  font-weight: 600;
  cursor: pointer;
  box-shadow: 0 4px 12px rgba(33,103,174,0.25);
  transition: transform 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;
}

[selector="completado-screen"] .btn-continuar:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(33,103,174,0.32);
  background: #1a558f;
}

[selector="completado-screen"] .btn-continuar i {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
}

/* Logo institucional */
[selector="logo-completado"] {
  display: block;
  margin: 0 auto 20px auto;
  max-width: 160px;
  height: auto;
}

/* Animación entrada */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* CONTENEDOR PRINCIPAL DE ERROR */
[selector="error-screen"] {
  min-height: 50vh;
  display: grid;
  place-items: center;
  padding: 24px;
  background: var(--bg);
  color: var(--accent) !important;
}

[selector="error-screen"] .wrap,
[selector="error-screen"] .wrap * {
  color: var(--accent) !important;
}

[selector="error-screen"] .wrap {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 16px;
  box-shadow: var(--shadow);
  padding: clamp(28px, 4vw, 44px);
  text-align: center;
  animation: fadeIn .6s ease both;
}

/* Ícono grande superior (error) */
[selector="error-screen"] .wrap::before {
  content: "\f057"; /* fa-times-circle */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  display: block;
  font-size: 3rem;
  color: var(--danger) !important;
  margin-bottom: 14px;
  line-height: 1;
}

/* Título */
[selector="error-screen"] .titulo {
  font-size: 1.5rem;
  font-weight: 700;
  margin-bottom: 6px;
}

/* Párrafos descriptivos */
[selector="error-screen"] .descripcion {
  font-size: 0.98rem;
  margin: 6px 0;
}

/* Línea con icono + texto */
[selector="error-screen"] .linea-icono {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  margin-top: 10px;
  font-size: 0.98rem;
}

/* Icono interno de error */
[selector="error-screen"] .icon-error {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  font-size: 1.1rem;
  color: var(--danger) !important;
}

/* Badge para correos con error */
[selector="error-screen"] .lista-correos-error {
  display: inline-block;
  margin: 12px 0 8px;
  font-weight: 600;
  font-size: 0.98rem;
  letter-spacing: 0.2px;
  padding: 8px 16px;
  border-radius: 12px;
  background: rgba(220,38,38,0.06);
  border: 1px solid rgba(220,38,38,0.7);
  color: var(--danger) !important;
  word-break: break-word;
}

/* Nota final */
[selector="error-screen"] .nota {
  margin-top: 18px;
  font-size: 0.95rem;
  background: rgba(220,38,38,0.04);
  border: 1px dashed var(--danger);
  padding: 12px 16px;
  border-radius: 12px;
  color: var(--accent) !important;
}

/* Botón Continuar (lo reutilizamos con otro acento si quieres) */
[selector="error-screen"] .btn-continuar {
  margin-top: 20px;
  display: inline-flex;
  align-items: center;
