(function () {
  const MODAL_ID = 'modal_preventivo_crearCliente';
  const FOOTER_SUFFIX = '___BV_modal_footer_';

  // ⚙️ Helper genérico para setear campos en el form de PM4
  function setField(fieldName, val) {
    // Intenta setear directo en el form renderer de PM4
    try {
      const app = document.getElementById('vue-form-renderer');
      const vm = app && app.__vue__;
      if (vm && vm.formData && vm.formData._root) {
        vm.$set(vm.formData._root, fieldName, val);
        return;
      }
    } catch (e) {}

    // Fallback: si tienes un input oculto con ese name:
    const input = document.querySelector(`[name="${fieldName}"]`);
    if (input) {
      input.value = val;
      input.dispatchEvent(new Event('input', { bubbles: true }));
    }
  }

  // ⬇️ Guarda la última decisión también en window.* (útil si usarás un cálculo con return)
  function setDecision(val /* "true" | "false" */) {
    window.__crearClienteUltimaDecision = val; // <- memoria global sencilla

    // Actualiza el flag principal del crear cliente
    setField('frm_tom_cc_crear_cliente_flag', val);
  }

  function log(...args) { try { console.log('[PM4 MODAL DEBUG]', ...args); } catch (_) {} }

  function findModalFooter() {
    const id = `${MODAL_ID}${FOOTER_SUFFIX}`;
    const local = document.getElementById(id);
    const topDoc = (window.top && window.top.document) ? window.top.document : null;
    const topEl = topDoc ? topDoc.getElementById(id) : null;
    if (local) return { el: local, scope: 'local-document' };
    if (topEl) return { el: topEl, scope: 'top-document' };
    return null;
  }

  function bindFooterHandlers(footerInfo) {
    if (!footerInfo || !footerInfo.el) {
      log('No hay footer para enlazar (bindFooterHandlers)');
      return false;
    }
    const footer = footerInfo.el;

    const btnCancel = footer.querySelector('.btn.btn-secondary');
    const btnOk = footer.querySelector('.btn.btn-primary');

    if (!btnCancel && !btnOk) {
      log('Footer encontrado pero no hay botones .btn-primary / .btn-secondary', { scope: footerInfo.scope, footer });
      return false;
    }

    ['__bound_ok', '__bound_cancel'].forEach(flag => {
      if (btnOk && btnOk[flag]) btnOk.removeEventListener('click', btnOk[flag], true);
      if (btnCancel && btnCancel[flag]) btnCancel.removeEventListener('click', btnCancel[flag], true);
    });

    if (btnOk) {
      const okHandler = function (e) {
        log('CLICK OK detectado en', footerInfo.scope);
        setDecision("true");   // ⬅️ establece "true" como TEXTO
        // Si quieres también podrías setear frm_tomador_response_accion = "true":
        // setField('frm_tomador_response_accion', "true");

        // 🧹 Limpiar la respuesta para siguientes peticiones
        setField('tri_respuesta_tia_tomador', '');
      };
      btnOk.addEventListener('click', okHandler, true);
      btnOk.__bound_ok = okHandler;
    } else {
      log('No se encontró botón OK (.btn-primary)');
    }

    if (btnCancel) {
      const cancelHandler = function (e) {
        log('CLICK CANCEL detectado en', footerInfo.scope);
        setDecision("false");  // ⬅️ establece "false" como TEXTO
        // ⬇️ Actualiza frm_tomador_response_accion a "false"
        setField('frm_tomador_response_accion', "false");

        // 🧹 Limpiar también la respuesta al cancelar
        setField('tri_respuesta_tia_tomador', '');
      };
      btnCancel.addEventListener('click', cancelHandler, true);
      btnCancel.__bound_cancel = cancelHandler;
    } else {
      log('No se encontró botón Cancel (.btn-secondary)');
    }

    log('Handlers enlazados en', footerInfo.scope);
    return true;
  }

  function observeAndBind() {
    const tryBind = () => {
      const footerInfo = findModalFooter();
      if (footerInfo) {
        bindFooterHandlers(footerInfo);
        return true;
      }
      //log('Footer aún no disponible, esperando…');
      return false;
    };

    if (tryBind()) return;

    const obsConfig = { childList: true, subtree: true };
    const localObserver = new MutationObserver(() => { tryBind(); });
    localObserver.observe(document.body, obsConfig);

    if (window.top && window.top.document && window.top.document.body) {
      const topObserver = new MutationObserver(() => { tryBind(); });
      topObserver.observe(window.top.document.body, obsConfig);
      log('Observando DOM local y top para detectar el modal.');
    } else {
      log('No se pudo observar window.top.document (posible restricción).');
    }
  }

  log('Script de depuración cargado. URL:', location.href);
  observeAndBind();
})();

if(this.frm_tom_tipo_documento == '' || this.frm_tom_num_documento == ''){
