  }

const frm_tom_tipo_documento = this.frm_tom_tipo_documento
if (frm_tom_tipo_documento == "NIT")
return "NIT"
if (frm_tom_tipo_documento == "CED")
return "CC"

setTimeout(() => {
  const frm_tomador_response_accion = this.frm_tomador_response_accion;

  if (frm_tomador_response_accion == "true") {
    const boton = document.querySelector('[custom-css-selector="btn_preventivo_crearCliente"]');
    if (boton && boton.__vue__) {
      boton.__vue__.$root.$bvModal.show('modal_preventivo_crearCliente');
    }
  }
}, 600);

return this.frm_tomador_response_accion;

