function setField(fieldName, val) {
  try {
    const app = document.getElementById('vue-form-renderer');
    const vm  = app && app.__vue__;
    if (vm && vm.formData && vm.formData._root) {
      vm.$set(vm.formData._root, fieldName, val);
      return;
    }
  } catch (e) {
    // ignoramos errores silenciosamente
  }

  // Fallback: input oculto con ese name
  const input = document.querySelector(`[name="${fieldName}"]`);
  if (input) {
    input.value = val;
    input.dispatchEvent(new Event('input', { bubbles: true }));
  }
}

// ------------------ LÓGICA DE LA PROPIEDAD CALCULADA ------------------

const raw = String(this.tri_respuesta_tia_tomador || '');

const marker = 'Respuesta:';
let esNulo = false;

const idx = raw.indexOf(marker);
if (idx !== -1) {
  const jsonStr = raw.substring(idx + marker.length).trim();
  try {
    const obj = JSON.parse(jsonStr);
    if (obj && Object.prototype.hasOwnProperty.call(obj, 'value') && obj.value === null) {
      esNulo = true;
    }
  } catch (e) {
    // si falla el parseo, seguimos con el fallback
  }
}

if (!esNulo && raw.includes('"value":null')) {
  esNulo = true;
}

// Resultado final de la propiedad
const result = esNulo ? "true" : "false";

// 🔄 Limpiamos la variable para siguientes peticiones
setField('tri_respuesta_tia_tomador', null);

// Devolvemos el flag en STRING
return result;

