    if (v === null || v === undefined) return false;

    const str = String(v).trim();

    if (str === "" || str === "0") return false;

    const num = Number(str);
    if (Number.isFinite(num) && num === 0) return false;

    return true;
  };

  const tieneAlgo =
    hasRealValue(this.grd_valores_asegurados_deducibles_seleccion);

  return tieneAlgo ? "true" : "false";

const opcionSel = String(this.grd_valores_asegurados_deducibles_seleccion ?? "").trim();
    const moneda = String(this.frm_cot_moneda ?? "").trim();

