    const prima = String(fila?.grd_prima_antes_iva ?? "").trim();

    if (!opcionSel || !prima) return "";

    return `${opcionSel}: ${moneda} ${prima} + IVA`;

const opcionSel = String(this.grd_valores_asegurados_deducibles_seleccion ?? "").trim();
